CREATE TABLE DOI (
    doi_address varchar(70) PRIMARY KEY,
    doi_title varchar(300),
    -- author
    pub_date varchar(10),
    doi_url varchar(100),
    -- keywords
    abstract varchar(3100),
    publisher varchar(40),
    field varchar(100)
);
CREATE TABLE FUSION_METHOD (
    m_name varchar(100),
    m_key varchar(100) PRIMARY KEY,
    m_doi varchar(70),
    m_desc varchar(400),
    u1 varchar(450),
    u3 varchar(500)
);

CREATE TABLE DATA (
  d_doi varchar(70),
  d_name varchar(70) PRIMARY KEY,
  d_url varchar(100),
  method_key varchar(100),
  collection_method varchar(150),
  u2 varchar(600),
  FOREIGN KEY (d_doi) REFERENCES DOI(doi_address),
  FOREIGN KEY (method_key) REFERENCES FUSION_METHOD(m_key)
);
CREATE TABLE DOI_AUTHOR(
    a_doi varchar(70),
    author varchar(50),
    PRIMARY KEY (a_doi, author),
    FOREIGN KEY (a_doi) REFERENCES DOI(doi_address)
);
-- Table: DOI

